"""Embedded, dependency-free Auro operator console assets."""
from __future__ import annotations

HTML = r'''<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="color-scheme" content="dark"><title>Auro Operator Console</title><link rel="stylesheet" href="/console.css"></head>
<body><a class="skip" href="#main">Skip to workbench</a>
<header class="mast"><div><p class="eyebrow">AURUM ORGANISMUS XIV · AOX–HIM</p><h1>Auro operator console</h1><p class="lede">A sovereign instrument for model responses, native capabilities, and receipt-backed work.</p></div><div class="connection"><span id="light" aria-hidden="true"></span><span id="connection">Connecting</span></div></header>
<nav aria-label="Console sections"><a href="#workbench">Workbench</a><a href="#registry">Registry</a><a href="#receipts">Receipt room</a></nav>
<main id="main"><section class="rail" aria-label="Runtime status"><div><span>Service</span><strong id="service">—</strong></div><div><span>Model</span><strong id="model">Configured at response time</strong></div><div><span>Capabilities</span><strong id="capCount">—</strong></div><div><span>Proof posture</span><strong>Receipt-backed · local-first</strong></div></section>
<section id="workbench" class="grid"><div class="panel compose"><p class="kicker">01 · Workbench</p><h2>Ask the organism</h2><form id="ask"><label for="message">Objective</label><textarea id="message" required maxlength="12000" placeholder="Give Auro a concrete objective…"></textarea><div class="execute"><label><input id="execute" type="checkbox"> Allow governed execution</label><input id="token" type="password" autocomplete="off" placeholder="Operator token (memory only)" aria-label="Operator token" hidden></div><button type="submit">Ask Auro <span aria-hidden="true">→</span></button></form></div>
<article class="panel response" aria-live="polite"><div class="response-head"><div><p class="kicker">02 · Response</p><h2 id="responseTitle">Awaiting an objective</h2></div><span id="confidence"></span></div><div id="answer" class="answer"><p class="muted">The response, bounded reasoning summary, internal council, proposed actions, and receipt will appear here.</p></div><details><summary>Evidence and council</summary><pre id="evidence">No response yet.</pre></details></article></section>
<section id="registry" class="section"><div class="section-head"><div><p class="kicker">03 · Native substrate</p><h2>Capability registry</h2></div><label class="search">Filter <input id="filter" type="search" placeholder="organ, capability, mode"></label></div><div id="capabilities" class="registry" aria-live="polite"></div></section>
<section id="receipts" class="section receipts"><div class="section-head"><div><p class="kicker">04 · Chain of custody</p><h2>Receipt room</h2></div><button id="verify" class="secondary">Verify chain</button></div><p id="verification" class="muted">Not yet verified.</p><div id="receiptList" class="receipt-list"></div></section></main>
<footer><p>Auro14B · HIM — NOVA / MESIE lineage</p><p>Paper/testnet finance only · integrity vault is not encrypted custody</p></footer><script src="/console.js" defer></script></body></html>'''

CSS = r''':root{--canvas:#10110f;--surface:#171915;--raised:#20231d;--ink:#f1eee4;--muted:#aaa99e;--quiet:#777b70;--signal:#d9a441;--good:#6fb58a;--danger:#d76d61;--rule:#34382f;--focus:#f2c66d;font-family:Inter,ui-sans-serif,system-ui,sans-serif;color:var(--ink);background:var(--canvas)}*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;min-width:320px;background:var(--canvas);line-height:1.55}.skip{position:fixed;left:12px;top:-60px;background:var(--ink);color:var(--canvas);padding:8px 12px;z-index:10}.skip:focus{top:12px}.mast{max-width:1280px;margin:auto;padding:64px 32px 40px;display:flex;justify-content:space-between;gap:32px;align-items:flex-start;border-bottom:1px solid var(--rule)}h1,h2,p{margin-top:0}h1{font:400 clamp(2.4rem,6vw,5.8rem)/.95 Georgia,serif;max-width:760px;letter-spacing:-.045em;margin-bottom:24px}h2{font:400 clamp(1.55rem,3vw,2.4rem)/1.1 Georgia,serif;letter-spacing:-.025em}.eyebrow,.kicker{font:700 .68rem/1.2 ui-monospace,monospace;letter-spacing:.15em;text-transform:uppercase;color:var(--signal)}.lede{color:var(--muted);max-width:650px;font-size:1.05rem}.connection{display:flex;align-items:center;gap:9px;white-space:nowrap;color:var(--muted);font-size:.8rem}#light{width:8px;height:8px;background:var(--signal);display:inline-block}#light.ok{background:var(--good)}#light.bad{background:var(--danger)}nav{max-width:1280px;margin:auto;padding:14px 32px;display:flex;gap:24px;border-bottom:1px solid var(--rule);position:sticky;top:0;background:rgba(16,17,15,.96);z-index:5}nav a{color:var(--muted);font-size:.78rem;text-decoration:none}nav a:hover{color:var(--ink)}main{max-width:1280px;margin:auto;padding:32px}.rail{display:grid;grid-template-columns:repeat(4,1fr);border:1px solid var(--rule);margin-bottom:32px}.rail div{padding:14px 16px;border-right:1px solid var(--rule)}.rail div:last-child{border:0}.rail span{display:block;color:var(--quiet);font-size:.68rem;text-transform:uppercase;letter-spacing:.08em}.rail strong{font-size:.82rem;font-weight:600}.grid{display:grid;grid-template-columns:minmax(300px,.85fr) minmax(0,1.4fr);gap:16px}.panel,.section{border:1px solid var(--rule);background:var(--surface);padding:28px}.compose{align-self:start;position:sticky;top:68px}label{display:block;color:var(--muted);font-size:.76rem;margin-bottom:8px}textarea,input[type=search],input[type=password]{width:100%;background:var(--canvas);border:1px solid var(--rule);border-radius:2px;color:var(--ink);font:inherit;padding:12px}textarea{min-height:210px;resize:vertical}textarea:focus,input:focus,button:focus,summary:focus,a:focus{outline:2px solid var(--focus);outline-offset:3px}.execute{margin:16px 0}.execute label{display:flex;gap:8px;align-items:center}.execute input[type=password]{margin-top:12px}button{border:1px solid var(--signal);border-radius:2px;background:var(--signal);color:#17130b;padding:11px 15px;font:700 .78rem/1 system-ui;cursor:pointer}button:hover{filter:brightness(1.08)}button:disabled{opacity:.5;cursor:wait}.secondary{background:transparent;color:var(--ink);border-color:var(--rule)}.response{min-height:510px}.response-head,.section-head{display:flex;justify-content:space-between;gap:24px;align-items:flex-start}.answer{font-size:1rem;max-width:72ch;white-space:pre-wrap}.muted{color:var(--muted)}details{border-top:1px solid var(--rule);margin-top:28px;padding-top:16px}summary{cursor:pointer;color:var(--muted);font-size:.8rem}pre{white-space:pre-wrap;overflow:auto;color:#c9cbbf;background:var(--canvas);padding:16px;font:12px/1.55 ui-monospace,monospace;max-height:420px}.section{margin-top:16px}.search{width:min(280px,40%)}.registry{border-top:1px solid var(--rule)}.cap{display:grid;grid-template-columns:minmax(180px,1fr) 120px 90px minmax(240px,1.5fr);gap:16px;padding:14px 0;border-bottom:1px solid var(--rule);align-items:start}.cap code{color:var(--ink);font-size:.8rem}.tag{font:700 .62rem/1 ui-monospace,monospace;text-transform:uppercase;color:var(--signal)}.cap p{color:var(--muted);font-size:.78rem;margin:0}.receipt-list{display:grid;gap:8px}.receipt{display:grid;grid-template-columns:140px 1fr 90px;gap:16px;padding:10px 0;border-top:1px solid var(--rule);font:12px/1.4 ui-monospace,monospace;color:var(--muted)}.receipt code{overflow:hidden;text-overflow:ellipsis}footer{max-width:1280px;margin:32px auto 0;padding:24px 32px 48px;border-top:1px solid var(--rule);display:flex;justify-content:space-between;color:var(--quiet);font-size:.7rem}footer p{margin:0}@media(max-width:800px){.mast{padding-top:40px;display:block}.connection{margin-top:24px}.rail{grid-template-columns:1fr 1fr}.rail div:nth-child(2){border-right:0}.rail div:nth-child(-n+2){border-bottom:1px solid var(--rule)}.grid{grid-template-columns:1fr}.compose{position:static}.cap{grid-template-columns:1fr 80px}.cap p{grid-column:1/-1}.search{width:100%}.section-head{display:block}.receipt{grid-template-columns:1fr}.mast,main,nav,footer{padding-left:18px;padding-right:18px}footer{display:block}footer p+ p{margin-top:8px}}@media(prefers-reduced-motion:reduce){html{scroll-behavior:auto}}'''

JS = r'''const $=s=>document.querySelector(s);const state={caps:[]};
async function api(path,options={}){const r=await fetch(path,options);let data={};try{data=await r.json()}catch{}if(!r.ok)throw new Error(data.detail||data.error||`HTTP ${r.status}`);return data}
function auth(){const token=$('#token').value;return token?{'authorization':`Bearer ${token}`}:{}}
function esc(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
async function boot(){try{const [h,c,r]=await Promise.all([api('/health'),api('/v1/capabilities'),api('/v1/receipts')]);$('#service').textContent=h.service;$('#capCount').textContent=c.capabilities.length;state.caps=c.capabilities;renderCaps();renderReceipts(r.receipts);$('#connection').textContent='Runtime online';$('#light').className='ok'}catch(e){$('#connection').textContent='Runtime unavailable';$('#light').className='bad';$('#answer').innerHTML=`<p class="muted">${esc(e.message)}</p>`}}
function renderCaps(){const q=$('#filter').value.toLowerCase();const rows=state.caps.filter(c=>JSON.stringify(c).toLowerCase().includes(q));$('#capabilities').innerHTML=rows.map(c=>`<article class="cap"><code>${esc(c.name)}</code><span class="tag">${esc(c.organ)}</span><span class="tag">${c.approval_required?'approval':'read'}</span><p>${esc(c.description)}</p></article>`).join('')||'<p class="muted">No matching capabilities.</p>'}
function renderReceipts(rows=[]){$('#receiptList').innerHTML=rows.map(r=>`<div class="receipt"><span>${esc(r.kind||r.operation)}</span><code title="${esc(r.hash)}">${esc(r.hash)}</code><span>${r.ok?'accepted':'denied'}</span></div>`).join('')||'<p class="muted">No receipts recorded in this process.</p>'}
$('#execute').addEventListener('change',e=>{$('#token').hidden=!e.target.checked;if(!e.target.checked)$('#token').value=''})
$('#filter').addEventListener('input',renderCaps)
$('#ask').addEventListener('submit',async e=>{e.preventDefault();const btn=e.submitter;btn.disabled=true;$('#responseTitle').textContent='Council working…';$('#answer').innerHTML='<p class="muted">Interpreting, deliberating, and verifying.</p>';try{const execute=$('#execute').checked;const data=await api('/v1/respond',{method:'POST',headers:{'content-type':'application/json',...auth()},body:JSON.stringify({message:$('#message').value,execute})});$('#model').textContent=`${data.model.model}${data.model.parameter_count_verified?` · ${data.model.parameter_count.toLocaleString()} verified params`:' · parameters unverified'}`;$('#responseTitle').textContent='Auro response';$('#confidence').textContent=`${Math.round(data.confidence*100)}% confidence`;$('#answer').textContent=data.answer;$('#evidence').textContent=JSON.stringify({reasoning_summary:data.reasoning_summary,agents:data.agents,proposed_actions:data.proposed_actions,executions:data.executions,receipt:data.receipt},null,2);await refreshReceipts()}catch(err){$('#responseTitle').textContent='Request failed';$('#answer').innerHTML=`<p class="muted">${esc(err.message)}</p>`}finally{btn.disabled=false}})
async function refreshReceipts(){const r=await api('/v1/receipts');renderReceipts(r.receipts)}
$('#verify').addEventListener('click',async()=>{try{const r=await api('/v1/receipts/verify');$('#verification').textContent=r.ok?`Chain valid · ${r.count??r.receipts??'all'} receipts checked`:`Chain invalid · ${r.reason||'verification failed'}`}catch(e){$('#verification').textContent=`Verification failed · ${e.message}`}})
document.addEventListener('keydown',e=>{if((e.ctrlKey||e.metaKey)&&e.key==='Enter')$('#ask').requestSubmit()});boot();'''

ASSETS = {
    "/": ("text/html; charset=utf-8", HTML.encode()),
    "/console": ("text/html; charset=utf-8", HTML.encode()),
    "/console.css": ("text/css; charset=utf-8", CSS.encode()),
    "/console.js": ("text/javascript; charset=utf-8", JS.encode()),
}

